// CSD_RATIONALE_BEGIN
// This strategy uses a Crane-style approach where we first generate an unconstrained sequence
// of tokens until we reach the length of the constrained window. Then, we switch to constrained
// decoding to ensure the expression is complete and compact. If the last token is the delimiter,
// we rollback to the last valid prefix before it.
// CSD_RATIONALE_END

generated := [];
var delimiter := new Delimiter(LeftDelimiter, RightDelimiter);
var helpers := new CSDHelpers(lm, parser, delimiter);
var stepsLeft := maxSteps;

while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  if (stepsLeft >= delimiter.Length)
  {
    // Generate unconstrained tokens until we reach the delimiter
    var next, newSteps := helpers.UnconstrainedStep(prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  }
  else
  {
    // Generate constrained tokens to ensure the expression is complete and compact
    var next, newSteps := helpers.ConstrainedStep(prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  }

  // Check if the last token is the delimiter and rollback if necessary
  if (|generated| > 0 && generated[|generated|-1] == delimiter.LeftDelimiter)
  {
    generated := helpers.RollbackToValidPrefix(generated);
  }
}

